const extractActiveLabel = (value: unknown): string | number | null => {
  if (!value || typeof value !== 'object') {
    return null;
  }
  const candidate = (value as { activeLabel?: unknown }).activeLabel;
  if (typeof candidate === 'string' || typeof candidate === 'number') {
    return candidate;
  }
  return null;
};

const ChannelNumbersSummary = () => {
  const dispatch = useAppDispatch();
  const theme = useMantineTheme();
  const isMobile = useMediaQuery(`(max-width: ${theme.breakpoints.sm})`);
  const isPortraitOrientation = useMediaQuery('(orientation: portrait)');
  const [searchParams, setSearchParams] = useSearchParams();
  const accountsState = useAppSelector(selectFinanceAccounts);
  const categoriesState = useAppSelector(selectFinanceCategories);
  const clientsState = useAppSelector(selectFinanceClients);
  const initialRange = useMemo<[Date | null, Date | null]>(() => {
    const startParam = searchParams.get(START_DATE_PARAM);
    const endParam = searchParams.get(END_DATE_PARAM);
    const parsedStart = startParam ? dayjs(startParam, DATE_FORMAT, true) : null;
    const parsedEnd = endParam ? dayjs(endParam, DATE_FORMAT, true) : null;
    if (parsedStart?.isValid() && parsedEnd?.isValid()) {
      return [parsedStart.toDate(), parsedEnd.toDate()];
    }
    return [dayjs().startOf('month').toDate(), dayjs().endOf('month').toDate()];
  }, [searchParams]);
  const initialPreset = useMemo<Preset>(() => {
    const startParam = searchParams.get(START_DATE_PARAM);
    const endParam = searchParams.get(END_DATE_PARAM);
    if (startParam && endParam) {
      return 'custom';
    }
    return 'thisMonth';
  }, [searchParams]);
  const [preset, setPreset] = useState<Preset>(initialPreset);
  const [range, setRange] = useState<[Date | null, Date | null]>(initialRange);
  const [summary, setSummary] = useState<ChannelNumbersSummaryType | null>(null);
  const [previousYearSummary, setPreviousYearSummary] = useState<ChannelNumbersSummaryType | null>(null);
  const [previousYearLoading, setPreviousYearLoading] = useState(false);
  const [attendeesChartGranularity, setAttendeesChartGranularity] = useState<ChartGranularity>('month');
  const [attendeesEntriesCurrent, setAttendeesEntriesCurrent] = useState<ChannelNumbersDetailEntry[]>([]);
  const [attendeesEntriesPrevious, setAttendeesEntriesPrevious] = useState<ChannelNumbersDetailEntry[]>([]);
  const [addonAttendeesEntriesCurrent, setAddonAttendeesEntriesCurrent] = useState<ChannelNumbersDetailEntry[]>([]);
  const [addonAttendeesEntriesPrevious, setAddonAttendeesEntriesPrevious] = useState<ChannelNumbersDetailEntry[]>([]);
  const [noShowEntriesCurrent, setNoShowEntriesCurrent] = useState<ChannelNumbersDetailEntry[]>([]);
  const [noShowEntriesPrevious, setNoShowEntriesPrevious] = useState<ChannelNumbersDetailEntry[]>([]);
  const [addonNoShowEntriesCurrent, setAddonNoShowEntriesCurrent] = useState<ChannelNumbersDetailEntry[]>([]);
  const [addonNoShowEntriesPrevious, setAddonNoShowEntriesPrevious] = useState<ChannelNumbersDetailEntry[]>([]);
  const [attendeesChartLoading, setAttendeesChartLoading] = useState(false);
  const [platformTrendFullscreen, setPlatformTrendFullscreen] = useState(false);
  const [activeTrendLabel, setActiveTrendLabel] = useState<string | number | null>(null);
  const [suppressTrendTooltip, setSuppressTrendTooltip] = useState(false);
  const [showDetailedMatrixMobile, setShowDetailedMatrixMobile] = useState(false);
  const fullscreenTrendChartAreaRef = useRef<HTMLDivElement | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedProductTypes, setSelectedProductTypes] = useState<string[]>([]);
  const [cashModal, setCashModal] = useState<CashModalState>({
    open: false,
    channel: null,
    amount: 0,
    currency: 'PLN',
    accountId: '',
    categoryId: '',
    counterpartyId: '',
    date: new Date(),
    description: '',
  });
  const [cashSubmitting, setCashSubmitting] = useState(false);
  const [cashMessage, setCashMessage] = useState<string | null>(null);
  const [detailModal, setDetailModal] = useState<DetailModalState>({
    open: false,
    loading: false,
    context: null,
    entries: [],
    totals: null,
    error: null,
  });
  const chartYear = useMemo(() => {
    if (summary?.endDate) {
      return dayjs(summary.endDate).year();
    }
    if (range[1]) {
      return dayjs(range[1]).year();
    }
    return dayjs().year();
  }, [summary?.endDate, range]);
  const trendAddonKeys = useMemo(
    () =>
      (summary?.addons ?? [])
        .filter((addon) => !isExcludedNoShowAddonName(addon.name))
        .map((addon) => addon.key),
    [summary?.addons],
  );

  const handlePresetChange = useCallback((value: Preset) => {
    setPreset(value);
    if (value === 'thisMonth') {
      setRange([dayjs().startOf('month').toDate(), dayjs().endOf('month').toDate()]);
      return;
    }
    if (value === 'lastMonth') {
      const lastMonthEnd = dayjs().startOf('month').subtract(1, 'day');
      setRange([lastMonthEnd.startOf('month').toDate(), lastMonthEnd.endOf('month').toDate()]);
      return;
    }
  }, []);

  const fetchSummary = useCallback(async (): Promise<ChannelNumbersSummaryType | null> => {
    const [start, end] = range;
    if (!start || !end) {
      return null;
    }
    const response = await fetchChannelNumbersBootstrap({
      startDate: dayjs(start).format(DATE_FORMAT),
      endDate: dayjs(end).format(DATE_FORMAT),
    });
    if (response?.finance) {
      dispatch(
        setFinanceBasics({
          accounts: response.finance.accounts ?? [],
          categories: response.finance.categories ?? [],
          vendors: response.finance.vendors ?? [],
          clients: response.finance.clients ?? [],
        }),
      );
    }
    return response.summary ?? null;
  }, [dispatch, range]);

  useEffect(() => {
    let isMounted = true;
    const run = async () => {
      setLoading(true);
      setError(null);
      try {
        const response = await fetchSummary();
        if (!isMounted) {
          return;
        }
        if (response) {
          setSummary(response);
        } else {
          setSummary(null);
        }
      } catch (err) {
        if (!isMounted) {
          return;
        }
        const message =
          (err as { response?: { data?: { message?: string } } })?.response?.data?.message ??
          (err as { message?: string }).message ??
          'Failed to load channel numbers';
        setError(message);
        setSummary(null);
      } finally {
        if (isMounted) {
          setLoading(false);
        }
      }
    };
    run();
    return () => {
      isMounted = false;
    };
  }, [fetchSummary]);

  useEffect(() => {
    let isMounted = true;
    const run = async () => {
      setPreviousYearLoading(true);
      try {
        const response = await fetchChannelNumbersSummary({
          startDate: dayjs(`${chartYear - 1}-01-01`).format(DATE_FORMAT),
          endDate: dayjs(`${chartYear - 1}-12-31`).format(DATE_FORMAT),
        });
        if (!isMounted) {
          return;
        }
        setPreviousYearSummary(response ?? null);
      } catch {
        if (isMounted) {
          setPreviousYearSummary(null);
        }
      } finally {
        if (isMounted) {
          setPreviousYearLoading(false);
        }
      }
    };

    run();
    return () => {
      isMounted = false;
    };
  }, [chartYear]);

  useEffect(() => {
    const currentStart = dayjs(`${chartYear}-01-01`).format(DATE_FORMAT);
    const currentEnd = dayjs(`${chartYear}-12-31`).format(DATE_FORMAT);
    const previousStart = dayjs(`${chartYear - 1}-01-01`).format(DATE_FORMAT);
    const previousEnd = dayjs(`${chartYear - 1}-12-31`).format(DATE_FORMAT);

    let isMounted = true;
    const fetchAddonMetricEntries = async (
      startDate: string,
      endDate: string,
      metric: 'addon' | 'addonNonShow',
    ) => {
      if (trendAddonKeys.length === 0) {
        return [] as ChannelNumbersDetailEntry[];
      }
      const responses = await Promise.all(
        trendAddonKeys.map((addonKey) =>
          fetchChannelNumbersDetails({
            startDate,
            endDate,
            metric,
            addonKey,
          }),
        ),
      );
      return responses.flatMap((response) => response.entries ?? []);
    };

    const run = async () => {
      setAttendeesChartLoading(true);
      try {
        const [
          currentDetails,
          previousDetails,
          currentNoShowDetails,
          previousNoShowDetails,
          currentAddonAttendeesDetails,
          previousAddonAttendeesDetails,
          currentAddonNoShowDetails,
          previousAddonNoShowDetails,
        ] = await Promise.all([
          fetchChannelNumbersDetails({
            startDate: currentStart,
            endDate: currentEnd,
            metric: 'normal',
          }),
          fetchChannelNumbersDetails({
            startDate: previousStart,
            endDate: previousEnd,
            metric: 'normal',
          }),
          fetchChannelNumbersDetails({
            startDate: currentStart,
            endDate: currentEnd,
            metric: 'nonShow',
          }),
          fetchChannelNumbersDetails({
            startDate: previousStart,
            endDate: previousEnd,
            metric: 'nonShow',
          }),
          fetchAddonMetricEntries(currentStart, currentEnd, 'addon'),
          fetchAddonMetricEntries(previousStart, previousEnd, 'addon'),
          fetchAddonMetricEntries(currentStart, currentEnd, 'addonNonShow'),
          fetchAddonMetricEntries(previousStart, previousEnd, 'addonNonShow'),
        ]);
        if (!isMounted) {
          return;
        }
        setAttendeesEntriesCurrent(currentDetails.entries ?? []);
        setAttendeesEntriesPrevious(previousDetails.entries ?? []);
        setAddonAttendeesEntriesCurrent(currentAddonAttendeesDetails);
        setAddonAttendeesEntriesPrevious(previousAddonAttendeesDetails);
        setNoShowEntriesCurrent(currentNoShowDetails.entries ?? []);
        setNoShowEntriesPrevious(previousNoShowDetails.entries ?? []);
        setAddonNoShowEntriesCurrent(currentAddonNoShowDetails);
        setAddonNoShowEntriesPrevious(previousAddonNoShowDetails);
      } catch {
        if (!isMounted) {
          return;
        }
        setAttendeesEntriesCurrent([]);
        setAttendeesEntriesPrevious([]);
        setAddonAttendeesEntriesCurrent([]);
        setAddonAttendeesEntriesPrevious([]);
        setNoShowEntriesCurrent([]);
        setNoShowEntriesPrevious([]);
        setAddonNoShowEntriesCurrent([]);
        setAddonNoShowEntriesPrevious([]);
      } finally {
        if (isMounted) {
          setAttendeesChartLoading(false);
        }
      }
    };

    run();
    return () => {
      isMounted = false;
    };
  }, [chartYear, trendAddonKeys]);

  useEffect(() => {
    const [start, end] = range;
    if (!start || !end) {
      return;
    }
    const startValue = dayjs(start).format(DATE_FORMAT);
    const endValue = dayjs(end).format(DATE_FORMAT);
    const currentStart = searchParams.get(START_DATE_PARAM);
    const currentEnd = searchParams.get(END_DATE_PARAM);
    if (currentStart === startValue && currentEnd === endValue) {
      return;
    }
    const nextParams = new URLSearchParams(searchParams);
    nextParams.set(START_DATE_PARAM, startValue);
    nextParams.set(END_DATE_PARAM, endValue);
    setSearchParams(nextParams, { replace: true });
  }, [range, searchParams, setSearchParams]);

  const productTypeGroups = useMemo<ProductTypeGroup[]>(() => {
    if (!summary) {
      return [];
    }
    const addonLookup = new Map<string, ChannelNumbersAddon>();
    (summary?.addons ?? []).forEach((addon) => {
      addonLookup.set(addon.key, addon);
    });

    const rawProducts =
      summary?.products && summary.products.length > 0
        ? summary.products
        : (() => {
            const grouped = new Map<
              number | string,
              {
                id: number | string;
                name: string;
                productTypeId: number | null;
                productTypeName: string | null;
                addonKeys: string[];
              }
            >();
            (summary?.addons ?? []).forEach((addon) => {
              const key = addon.productId ?? addon.productName ?? addon.key;
              const existing =
                grouped.get(key) ??
                {
                  id: addon.productId ?? key,
                  name: addon.productName ?? addon.name,
                  productTypeId: addon.productTypeId ?? null,
                  productTypeName: addon.productTypeName ?? null,
                  addonKeys: [],
                };
              existing.addonKeys.push(addon.key);
              grouped.set(key, existing);
            });
            return Array.from(grouped.values());
          })();

    const groups = new Map<string, ProductTypeGroup>();
    const ensureGroup = (typeId: number | string | null, typeName: string | null): ProductTypeGroup => {
      const slug = normalizeTypeName(typeName ?? 'Other');
      if (!groups.has(slug)) {
        groups.set(slug, {
          id: typeId ?? slug,
          name: typeName ?? 'Other',
          slug,
          products: [],
        });
      }
      return groups.get(slug)!;
    };

    rawProducts.forEach((product) => {
      const group = ensureGroup(product.productTypeId ?? `type-${product.id}`, product.productTypeName ?? null);
      const addons =
        (product.addonKeys ?? [])
          .map((key) => addonLookup.get(key))
          .filter((addon): addon is ChannelNumbersAddon => Boolean(addon)) ?? [];
      group.products.push({
        id: product.id,
        name: product.name,
        slug: normalizeTypeName(product.name),
        addons,
      });
    });

    if (groups.size === 0) {
      groups.set(MAIN_PRODUCT_TYPE_SLUG, {
        id: MAIN_PRODUCT_TYPE_SLUG,
        name: MAIN_PRODUCT_LABEL,
        slug: MAIN_PRODUCT_TYPE_SLUG,
        products: [
          {
            id: 'default-main',
            name: MAIN_PRODUCT_LABEL,
            slug: normalizeTypeName(MAIN_PRODUCT_LABEL),
            addons: [],
          },
        ],
      });
    }

    const prioritizedTypes = new Map<string, number>([
      [MAIN_PRODUCT_TYPE_SLUG, 0],
      [normalizeTypeName(ACTIVITY_PRODUCT_LABEL), 1],
    ]);

    const prioritizeMainProduct = (group: ProductTypeGroup) =>
      group.products.sort((a, b) => {
        if (group.slug === MAIN_PRODUCT_TYPE_SLUG) {
          const aIsPub = a.name.toLowerCase() === 'pub crawl';
          const bIsPub = b.name.toLowerCase() === 'pub crawl';
          if (aIsPub || bIsPub) {
            return Number(bIsPub) - Number(aIsPub);
          }
        }
        return a.name.localeCompare(b.name);
      });

    return Array.from(groups.values())
      .map((group) => ({
        ...group,
        products: prioritizeMainProduct(group),
      }))
      .sort((a, b) => {
        const aPriority = prioritizedTypes.get(a.slug);
        const bPriority = prioritizedTypes.get(b.slug);
        if (aPriority != null || bPriority != null) {
          return (aPriority ?? Number.MAX_SAFE_INTEGER) - (bPriority ?? Number.MAX_SAFE_INTEGER);
        }
        return a.name.localeCompare(b.name);
      });
  }, [summary]);

  const selectableProductTypes = useMemo(() => {
    const names = new Set(productTypeGroups.map((group) => group.name));
    return Array.from(names);
  }, [productTypeGroups]);

  const accountOptions = useMemo(
    () =>
      accountsState.data
        .filter((account) => (account.type === 'cash' || account.type === 'bank') && (account.isActive ?? true))
        .map((account) => ({
          value: String(account.id),
          label: account.currency ? `${account.name} (${account.currency})` : account.name,
        })),
    [accountsState.data],
  );

  const incomeCategoryOptions = useMemo(
    () =>
      categoriesState.data
        .filter((category) => category.kind === 'income')
        .map((category) => ({ value: String(category.id), label: category.name })),
    [categoriesState.data],
  );

  const clientOptions = useMemo(
    () => clientsState.data.map((client) => ({ value: String(client.id), label: client.name })),
    [clientsState.data],
  );

  const resolveDefaultAccountId = useCallback(
    (currencyCode: string): string => {
      if (!accountsState.data.length) {
        return '';
      }
      const normalizedCurrency = currencyCode?.toUpperCase() || 'PLN';
      const matchingCashAccount = accountsState.data.find(
        (account) => account.type === 'cash' && (account.currency ?? '').toUpperCase() === normalizedCurrency,
      );
      if (matchingCashAccount) {
        return String(matchingCashAccount.id);
      }
      const anyCash = accountsState.data.find((account) => account.type === 'cash');
      if (anyCash) {
        return String(anyCash.id);
      }
      return String(accountsState.data[0].id);
    },
    [accountsState.data],
  );

  const resolveDefaultCategoryId = useCallback((): string => {
    if (!incomeCategoryOptions.length) {
      return '';
    }
    return incomeCategoryOptions[0].value;
  }, [incomeCategoryOptions]);

  useEffect(() => {
    if (selectableProductTypes.length === 0) {
      setSelectedProductTypes([]);
      return;
    }
    setSelectedProductTypes((prev) => {
      const prevKey = [...prev].sort().join('|');
      const nextKey = [...selectableProductTypes].sort().join('|');
      if (prevKey === nextKey) {
        return prev;
      }
      return selectableProductTypes;
    });
  }, [selectableProductTypes]);

  const visibleTypeGroups = useMemo(() => {
    if (selectedProductTypes.length === 0) {
      return productTypeGroups;
    }
    const selected = new Set(selectedProductTypes);
    return productTypeGroups.filter((group) => selected.has(group.name));
  }, [productTypeGroups, selectedProductTypes]);

  const totalTypeColumns = useMemo(
    () => visibleTypeGroups.reduce((sum, group) => sum + getTypeColumnCount(group), 0),
    [visibleTypeGroups],
  );
  const selectedTypeSlugs = useMemo(
    () => new Set(selectedProductTypes.map((name) => normalizeTypeName(name))),
    [selectedProductTypes],
  );
  const isProductTypeFilterActive = useMemo(() => {
    if (selectedTypeSlugs.size === 0 || selectableProductTypes.length === 0) {
      return false;
    }
    return selectableProductTypes.some((typeName) => !selectedTypeSlugs.has(normalizeTypeName(typeName)));
  }, [selectableProductTypes, selectedTypeSlugs]);
  const currentAggregates = useMemo(
    () => aggregateMetricsByProductType(summary, selectedTypeSlugs.size > 0 ? selectedTypeSlugs : null),
    [summary, selectedTypeSlugs],
  );
  const currentProductTypeLookup = useMemo(() => buildProductTypeLookup(summary), [summary]);
  const previousProductTypeLookup = useMemo(
    () => buildProductTypeLookup(previousYearSummary),
    [previousYearSummary],
  );
  const filteredAttendeesCurrent = useMemo(
    () =>
      isProductTypeFilterActive
        ? filterEntriesBySelectedTypes(attendeesEntriesCurrent, selectedTypeSlugs, currentProductTypeLookup)
        : attendeesEntriesCurrent,
    [attendeesEntriesCurrent, currentProductTypeLookup, isProductTypeFilterActive, selectedTypeSlugs],
  );
  const filteredAttendeesPrevious = useMemo(
    () =>
      isProductTypeFilterActive
        ? filterEntriesBySelectedTypes(attendeesEntriesPrevious, selectedTypeSlugs, previousProductTypeLookup)
        : attendeesEntriesPrevious,
    [attendeesEntriesPrevious, isProductTypeFilterActive, previousProductTypeLookup, selectedTypeSlugs],
  );
  const filteredNoShowCurrent = useMemo(
    () =>
      isProductTypeFilterActive
        ? filterEntriesBySelectedTypes(noShowEntriesCurrent, selectedTypeSlugs, currentProductTypeLookup)
        : noShowEntriesCurrent,
    [currentProductTypeLookup, isProductTypeFilterActive, noShowEntriesCurrent, selectedTypeSlugs],
  );
  const filteredNoShowPrevious = useMemo(
    () =>
      isProductTypeFilterActive
        ? filterEntriesBySelectedTypes(noShowEntriesPrevious, selectedTypeSlugs, previousProductTypeLookup)
        : noShowEntriesPrevious,
    [isProductTypeFilterActive, noShowEntriesPrevious, previousProductTypeLookup, selectedTypeSlugs],
  );
  const filteredAddonAttendeesCurrent = useMemo(
    () =>
      isProductTypeFilterActive
        ? filterEntriesBySelectedTypes(
            addonAttendeesEntriesCurrent,
            selectedTypeSlugs,
            currentProductTypeLookup,
          )
        : addonAttendeesEntriesCurrent,
    [addonAttendeesEntriesCurrent, currentProductTypeLookup, isProductTypeFilterActive, selectedTypeSlugs],
  );
  const filteredAddonAttendeesPrevious = useMemo(
    () =>
      isProductTypeFilterActive
        ? filterEntriesBySelectedTypes(
            addonAttendeesEntriesPrevious,
            selectedTypeSlugs,
            previousProductTypeLookup,
          )
        : addonAttendeesEntriesPrevious,
    [addonAttendeesEntriesPrevious, isProductTypeFilterActive, previousProductTypeLookup, selectedTypeSlugs],
  );
  const filteredAddonNoShowCurrent = useMemo(
    () =>
      isProductTypeFilterActive
        ? filterEntriesBySelectedTypes(
            addonNoShowEntriesCurrent,
            selectedTypeSlugs,
            currentProductTypeLookup,
          )
        : addonNoShowEntriesCurrent,
    [addonNoShowEntriesCurrent, currentProductTypeLookup, isProductTypeFilterActive, selectedTypeSlugs],
  );
  const filteredAddonNoShowPrevious = useMemo(
    () =>
      isProductTypeFilterActive
        ? filterEntriesBySelectedTypes(
            addonNoShowEntriesPrevious,
            selectedTypeSlugs,
            previousProductTypeLookup,
          )
        : addonNoShowEntriesPrevious,
    [addonNoShowEntriesPrevious, isProductTypeFilterActive, previousProductTypeLookup, selectedTypeSlugs],
  );
  const filteredTotalNoShowCurrent = useMemo(
    () => [...filteredNoShowCurrent, ...filteredAddonNoShowCurrent],
    [filteredAddonNoShowCurrent, filteredNoShowCurrent],
  );
  const filteredTotalNoShowPrevious = useMemo(
    () => [...filteredNoShowPrevious, ...filteredAddonNoShowPrevious],
    [filteredAddonNoShowPrevious, filteredNoShowPrevious],
  );
  const filteredTotalAttendeesCurrent = useMemo(
    () => [...filteredAttendeesCurrent, ...filteredAddonAttendeesCurrent],
    [filteredAddonAttendeesCurrent, filteredAttendeesCurrent],
  );
  const filteredTotalAttendeesPrevious = useMemo(
    () => [...filteredAttendeesPrevious, ...filteredAddonAttendeesPrevious],
    [filteredAddonAttendeesPrevious, filteredAttendeesPrevious],
  );
  const attendeesComparisonData = useMemo(() => {
    if (attendeesChartGranularity === 'year') {
      const lastYearAttendees = filteredTotalAttendeesPrevious.reduce(
        (sum, entry) => sum + (entry.attended ?? entry.value ?? 0),
        0,
      );
      const thisYearAttendees = filteredTotalAttendeesCurrent.reduce(
        (sum, entry) => sum + (entry.attended ?? entry.value ?? 0),
        0,
      );
      const lastYearNoShow = filteredTotalNoShowPrevious.reduce((sum, entry) => {
        if (isExcludedNoShowAddonName(entry.addonName)) {
          return sum;
        }
        return sum + (entry.value ?? entry.nonShow ?? 0);
      }, 0);
      const thisYearNoShow = filteredTotalNoShowCurrent.reduce((sum, entry) => {
        if (isExcludedNoShowAddonName(entry.addonName)) {
          return sum;
        }
        return sum + (entry.value ?? entry.nonShow ?? 0);
      }, 0);
      return [
        { label: String(chartYear - 1), attendees: lastYearAttendees + lastYearNoShow },
        { label: String(chartYear), attendees: thisYearAttendees + thisYearNoShow },
      ];
    }

    if (attendeesChartGranularity === 'month') {
      const monthLabels = Array.from({ length: 12 }, (_, index) =>
        dayjs().month(index).startOf('month').format('MMM'),
      );
      const thisYearByMonth = new Map<number, number>();
      const lastYearByMonth = new Map<number, number>();

      filteredTotalAttendeesCurrent.forEach((entry) => {
        const date = dayjs(entry.counterDate);
        if (date.year() !== chartYear) {
          return;
        }
        const month = date.month();
        thisYearByMonth.set(month, (thisYearByMonth.get(month) ?? 0) + (entry.attended ?? entry.value ?? 0));
      });

      filteredTotalAttendeesPrevious.forEach((entry) => {
        const date = dayjs(entry.counterDate);
        if (date.year() !== chartYear - 1) {
          return;
        }
        const month = date.month();
        lastYearByMonth.set(month, (lastYearByMonth.get(month) ?? 0) + (entry.attended ?? entry.value ?? 0));
      });
      filteredTotalNoShowCurrent.forEach((entry) => {
        if (isExcludedNoShowAddonName(entry.addonName)) {
          return;
        }
        const date = dayjs(entry.counterDate);
        if (date.year() !== chartYear) {
          return;
        }
        const month = date.month();
        thisYearByMonth.set(month, (thisYearByMonth.get(month) ?? 0) + (entry.value ?? entry.nonShow ?? 0));
      });
      filteredTotalNoShowPrevious.forEach((entry) => {
        if (isExcludedNoShowAddonName(entry.addonName)) {
          return;
        }
        const date = dayjs(entry.counterDate);
        if (date.year() !== chartYear - 1) {
          return;
        }
        const month = date.month();
        lastYearByMonth.set(month, (lastYearByMonth.get(month) ?? 0) + (entry.value ?? entry.nonShow ?? 0));
      });

      return monthLabels.map((label, month) => ({
        label,
        thisYear: thisYearByMonth.get(month) ?? 0,
        lastYear: lastYearByMonth.get(month) ?? 0,
      }));
    }

    const weekCount = Math.ceil(getDaysInYear(chartYear) / 7);
    const thisYearByWeek = new Map<number, number>();
    const lastYearByWeek = new Map<number, number>();

    filteredTotalAttendeesCurrent.forEach((entry) => {
      const date = dayjs(entry.counterDate);
      if (date.year() !== chartYear) {
        return;
      }
      const weekIndex = getWeekIndexWithinYear(date, chartYear);
      if (!weekIndex) {
        return;
      }
      thisYearByWeek.set(weekIndex, (thisYearByWeek.get(weekIndex) ?? 0) + (entry.attended ?? entry.value ?? 0));
    });

    filteredTotalAttendeesPrevious.forEach((entry) => {
      const date = dayjs(entry.counterDate);
      if (date.year() !== chartYear - 1) {
        return;
      }
      const weekIndex = getWeekIndexWithinYear(date, chartYear - 1);
      if (!weekIndex) {
        return;
      }
      lastYearByWeek.set(weekIndex, (lastYearByWeek.get(weekIndex) ?? 0) + (entry.attended ?? entry.value ?? 0));
    });
    filteredTotalNoShowCurrent.forEach((entry) => {
      if (isExcludedNoShowAddonName(entry.addonName)) {
        return;
      }
      const date = dayjs(entry.counterDate);
      if (date.year() !== chartYear) {
        return;
      }
      const weekIndex = getWeekIndexWithinYear(date, chartYear);
      if (!weekIndex) {
        return;
      }
      thisYearByWeek.set(weekIndex, (thisYearByWeek.get(weekIndex) ?? 0) + (entry.value ?? entry.nonShow ?? 0));
    });
    filteredTotalNoShowPrevious.forEach((entry) => {
      if (isExcludedNoShowAddonName(entry.addonName)) {
        return;
      }
      const date = dayjs(entry.counterDate);
      if (date.year() !== chartYear - 1) {
        return;
      }
      const weekIndex = getWeekIndexWithinYear(date, chartYear - 1);
      if (!weekIndex) {
        return;
      }
      lastYearByWeek.set(weekIndex, (lastYearByWeek.get(weekIndex) ?? 0) + (entry.value ?? entry.nonShow ?? 0));
    });

    return Array.from({ length: weekCount }, (_, index) => {
      const weekNumber = index + 1;
      const thisYearStart = dayjs(`${chartYear}-01-01`).add((weekNumber - 1) * 7, 'day');
      const thisYearEnd = thisYearStart.add(6, 'day').year() === chartYear
        ? thisYearStart.add(6, 'day')
        : dayjs(`${chartYear}-12-31`);
      const lastYearStart = dayjs(`${chartYear - 1}-01-01`).add((weekNumber - 1) * 7, 'day');
      const lastYearEnd = lastYearStart.add(6, 'day').year() === chartYear - 1
        ? lastYearStart.add(6, 'day')
        : dayjs(`${chartYear - 1}-12-31`);
      return {
        label: String(weekNumber),
        weekNumber,
        thisYearRange: `${thisYearStart.format('MMM D')} - ${thisYearEnd.format('MMM D, YYYY')}`,
        lastYearRange: `${lastYearStart.format('MMM D')} - ${lastYearEnd.format('MMM D, YYYY')}`,
        thisYear: thisYearByWeek.get(weekNumber) ?? 0,
        lastYear: lastYearByWeek.get(weekNumber) ?? 0,
      };
    });
  }, [
    chartYear,
    attendeesChartGranularity,
    filteredTotalAttendeesCurrent,
    filteredTotalAttendeesPrevious,
    filteredTotalNoShowCurrent,
    filteredTotalNoShowPrevious,
  ]);
  const mobileChannelRows = useMemo(() => {
    if (!summary) {
      return [];
    }
    return summary.channels
      .map((channel) => {
        const breakdown = currentAggregates.channelBreakdown.get(channel.channelId) ?? {
          attendees: 0,
          noShow: 0,
          platformTotal: 0,
        };
        return {
          channelId: channel.channelId,
          channelName: channel.channelName,
          ...breakdown,
        };
      })
      .sort((a, b) => b.platformTotal - a.platformTotal);
  }, [currentAggregates.channelBreakdown, summary]);
  const chartXAxisInterval = useMemo(() => {
    if (!isMobile) {
      return 'preserveStartEnd' as const;
    }
    if (attendeesChartGranularity === 'week') {
      return 5;
    }
    return 0;
  }, [attendeesChartGranularity, isMobile]);

  useEffect(() => {
    setActiveTrendLabel(null);
    setSuppressTrendTooltip(false);
  }, [attendeesChartGranularity, platformTrendFullscreen]);

  useEffect(() => {
    if (!platformTrendFullscreen) {
      return;
    }

    const handlePointerDown = (event: PointerEvent) => {
      const chartArea = fullscreenTrendChartAreaRef.current;
      const target = event.target;
      if (!chartArea || !(target instanceof Node)) {
        return;
      }
      if (!chartArea.contains(target)) {
        setActiveTrendLabel((prev) => (prev === null ? prev : null));
        setSuppressTrendTooltip((prev) => (prev ? prev : true));
      }
    };

    document.addEventListener('pointerdown', handlePointerDown, true);
    return () => {
      document.removeEventListener('pointerdown', handlePointerDown, true);
    };
  }, [platformTrendFullscreen]);

  const usePseudoLandscapeFullscreen = isMobile && isPortraitOrientation;
  const renderPlatformTrendChart = (
    height: number | string,
    expanded = false,
    forceLandscapeLayout = false,
  ) => {
    const axisInterval =
      expanded && isMobile
        ? attendeesChartGranularity === 'week'
          ? 5
          : 0
        : chartXAxisInterval;
    const useTouchTooltipMode = isMobile && expanded;
    const useGroupedTooltip = attendeesChartGranularity !== 'year';
    const useHorizontalBars = forceLandscapeLayout;
    const weekCategoryInterval = attendeesChartGranularity === 'week' ? (isMobile ? 1 : 0) : 0;
    return (
      <Box h={height} style={{ position: 'relative', overflow: 'visible' }}>
        <ResponsiveContainer width="100%" height="100%">
          <BarChart
            data={attendeesComparisonData}
            layout={useHorizontalBars ? 'vertical' : 'horizontal'}
            onMouseMove={(eventState: unknown) => {
              if (useTouchTooltipMode || !useGroupedTooltip) {
                return;
              }
              const nextLabel = extractActiveLabel(eventState);
              setActiveTrendLabel(nextLabel);
              if (nextLabel !== null) {
                setSuppressTrendTooltip((prev) => (prev ? false : prev));
              }
            }}
            onMouseLeave={() => {
              if (!useTouchTooltipMode) {
                setActiveTrendLabel(null);
                setSuppressTrendTooltip((prev) => (prev ? prev : true));
              }
            }}
            onClick={(eventState: unknown) => {
              if (!useGroupedTooltip) {
                return;
              }
              const nextLabel = extractActiveLabel(eventState);
              if (nextLabel !== null) {
                setActiveTrendLabel(nextLabel);
                setSuppressTrendTooltip((prev) => (prev ? false : prev));
              }
            }}
            margin={
              expanded
                ? useHorizontalBars
                  ? { top: 8, right: 12, left: 4, bottom: 8 }
                  : { top: 12, right: 12, left: 8, bottom: 16 }
                : { top: 8, right: isMobile ? 4 : 12, left: 0, bottom: 0 }
            }
            barCategoryGap={expanded ? (useHorizontalBars ? '22%' : '20%') : isMobile ? '28%' : '18%'}
          >
            <CartesianGrid strokeDasharray="3 3" />
            {useHorizontalBars ? (
              <>
                <XAxis
                  type="number"
                  orientation="top"
                  allowDecimals={false}
                  tick={{ fontSize: expanded ? 11 : isMobile ? 10 : 12 }}
                  tickMargin={8}
                />
                <YAxis
                  type="category"
                  dataKey="label"
                  interval={weekCategoryInterval}
                  tick={{ fontSize: expanded ? 11 : isMobile ? 10 : 12 }}
                  tickMargin={6}
                  width={attendeesChartGranularity === 'week' ? 28 : 36}
                />
              </>
            ) : (
              <>
                <XAxis
                  dataKey="label"
                  interval={axisInterval}
                  minTickGap={expanded ? 1 : isMobile ? 2 : 8}
                  tickMargin={expanded ? 10 : 4}
                  tick={{ fontSize: expanded ? 11 : isMobile ? 10 : 12 }}
                />
                <YAxis
                  allowDecimals={false}
                  tick={{ fontSize: expanded ? 11 : isMobile ? 10 : 12 }}
                  width={expanded ? 40 : isMobile ? 30 : 40}
                />
              </>
            )}
            {attendeesChartGranularity !== 'year' && (
              <Legend wrapperStyle={{ fontSize: expanded ? 12 : isMobile ? 11 : 12 }} />
            )}
            {useGroupedTooltip && activeTrendLabel !== null && (
              useHorizontalBars ? (
                <ReferenceArea
                  y1={activeTrendLabel}
                  y2={activeTrendLabel}
                  ifOverflow="extendDomain"
                  fill={theme.colors.blue[3]}
                  fillOpacity={0.5}
                  strokeOpacity={0}
                />
              ) : (
                <ReferenceArea
                  x1={activeTrendLabel}
                  x2={activeTrendLabel}
                  ifOverflow="extendDomain"
                  fill={theme.colors.blue[3]}
                  fillOpacity={0.5}
                  strokeOpacity={0}
                />
              )
            )}
            <Tooltip
              trigger={useTouchTooltipMode ? 'click' : 'hover'}
              active={suppressTrendTooltip ? false : undefined}
              shared={useGroupedTooltip}
              cursor={false}
              isAnimationActive={false}
              allowEscapeViewBox={{ x: true, y: true }}
              wrapperStyle={{ pointerEvents: 'none', zIndex: 1000 }}
              labelFormatter={(label: string | number) =>
                attendeesChartGranularity === 'week' ? `Week ${label}` : label
              }
              formatter={(value: number | string, name: string, item: { payload?: Record<string, unknown> }) => {
                const payload = item?.payload ?? {};
                if (attendeesChartGranularity === 'week') {
                  if (name === 'This year') {
                    return [
                      numberFormatter.format(Number(value) || 0),
                      `This year (${String(payload.thisYearRange ?? '')})`,
                    ];
                  }
                  if (name === 'Last year') {
                    return [
                      numberFormatter.format(Number(value) || 0),
                      `Last year (${String(payload.lastYearRange ?? '')})`,
                    ];
                  }
                }
                return [
                  numberFormatter.format(Number(value) || 0),
                  attendeesChartGranularity === 'year' ? 'Platform total' : name,
                ];
              }}
            />
            {attendeesChartGranularity === 'year' ? (
              <Bar
                dataKey="attendees"
                name="Platform total"
                fill={theme.colors.blue[6]}
                radius={useHorizontalBars ? [0, 6, 6, 0] : [6, 6, 0, 0]}
                isAnimationActive={false}
              />
            ) : (
              <>
                <Bar
                  dataKey="lastYear"
                  name="Last year"
                  fill={theme.colors.gray[5]}
                  radius={useHorizontalBars ? [0, 6, 6, 0] : [6, 6, 0, 0]}
                  isAnimationActive={false}
                />
                <Bar
                  dataKey="thisYear"
                  name="This year"
                  fill={theme.colors.blue[6]}
                  radius={useHorizontalBars ? [0, 6, 6, 0] : [6, 6, 0, 0]}
                  isAnimationActive={false}
                />
              </>
            )}
          </BarChart>
        </ResponsiveContainer>
      </Box>
    );
  };

  const cashSummary = summary?.cashSummary;
  const isLegacyRange = useMemo(() => {
    if (!summary?.endDate) {
      return false;
    }
    return dayjs(summary.endDate).isBefore(LEGACY_CUTOFF_DATE, 'day');
  }, [summary?.endDate]);
  const cashRows = useMemo(() => {
    const rows = cashSummary?.channels ?? [];
    if (!isLegacyRange) {
      return rows;
    }
    return rows.map((row) => ({
      ...row,
      collectedAmount: row.dueAmount,
      outstandingAmount: 0,
    }));
  }, [cashSummary?.channels, isLegacyRange]);
  const cashEntries = cashSummary?.entries ?? [];
  const cashTotals = useMemo(() => {
    const totals = cashSummary?.totals ?? [];
    if (!isLegacyRange) {
      return totals;
    }
    return totals.map((total) => ({
      ...total,
      collectedAmount: total.dueAmount,
      outstandingAmount: 0,
    }));
  }, [cashSummary?.totals, isLegacyRange]);
  const cashRangeIsCanonical = cashSummary?.rangeIsCanonical ?? false;

  const numberFormatter = useMemo(
    () =>
      new Intl.NumberFormat('en-US', {
        maximumFractionDigits: 0,
      }),
    [],
  );
  const formatCurrencyValue = useCallback((value: number, currency: string) => {
    try {
      return new Intl.NumberFormat(undefined, {
        style: 'currency',
        currency: currency || 'PLN',
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
      }).format(value || 0);
    } catch {
      return `${currency || 'PLN'} ${value.toFixed(2)}`;
    }
  }, []);

  const handleOpenCashModal = useCallback(
    (row: ChannelCashRow) => {
      if (!summary) {
        return;
      }
      const rangeLabel = `${dayjs(summary.startDate).format('MMM D, YYYY')} - ${dayjs(summary.endDate).format('MMM D, YYYY')}`;
      setCashModal({
        open: true,
        channel: row,
        amount: row.outstandingAmount > 0 ? row.outstandingAmount : row.dueAmount,
        currency: row.currency,
        accountId: resolveDefaultAccountId(row.currency),
        categoryId: resolveDefaultCategoryId(),
        counterpartyId: clientOptions[0]?.value ?? '',
        date: new Date(),
        description: `Cash collection for ${row.channelName} (${rangeLabel})`,
      });
      setCashMessage(null);
    },
    [clientOptions, resolveDefaultAccountId, resolveDefaultCategoryId, summary],
  );

  const handleCloseCashModal = useCallback(() => {
    setCashModal({
      open: false,
      channel: null,
      amount: 0,
      currency: 'PLN',
      accountId: '',
      categoryId: '',
      counterpartyId: '',
      date: new Date(),
      description: '',
    });
    setCashMessage(null);
  }, []);

  const handleCashSubmit = useCallback(async () => {
    if (!summary || !cashModal.channel) {
      setCashMessage('Select a channel entry before recording a collection.');
      return;
    }
    if (
      cashModal.amount <= 0 ||
      !cashModal.accountId ||
      !cashModal.categoryId ||
      !cashModal.counterpartyId
    ) {
      setCashMessage('Fill in the amount, account, category, and client.');
      return;
    }
    setCashSubmitting(true);
    setCashMessage(null);
    try {
      const transaction = await dispatch(
        createFinanceTransaction({
          kind: 'income',
          date: dayjs(cashModal.date).format('YYYY-MM-DD'),
          accountId: Number(cashModal.accountId),
          currency: cashModal.currency,
          amountMinor: Math.round(cashModal.amount * 100),
          categoryId: Number(cashModal.categoryId),
          counterpartyType: 'client',
          counterpartyId: Number(cashModal.counterpartyId),
          status: 'paid',
          description: cashModal.description || null,
          meta: {
            source: 'channel-numbers',
            channelId: cashModal.channel.channelId,
            rangeStart: summary.startDate,
            rangeEnd: summary.endDate,
          },
        }),
      ).unwrap();

      await recordChannelCashCollection({
        channelId: cashModal.channel.channelId,
        currency: cashModal.currency,
        amount: cashModal.amount,
        rangeStart: summary.startDate,
        rangeEnd: summary.endDate,
        financeTransactionId: transaction.id,
        note: cashModal.description,
      });
      handleCloseCashModal();
      await fetchSummary();
    } catch (err) {
      const message =
        (err as { response?: { data?: { message?: string } } })?.response?.data?.message ??
        (err as { message?: string }).message ??
        'Failed to record cash collection';
      setCashMessage(message);
    } finally {
      setCashSubmitting(false);
    }
  }, [cashModal, dispatch, fetchSummary, handleCloseCashModal, summary]);
  const handleCloseDetailModal = useCallback(() => {
    setDetailModal({
      open: false,
      loading: false,
      context: null,
      entries: [],
      totals: null,
      error: null,
    });
  }, []);

  const handleShowDetail = useCallback(
    (context: DrilldownContext) => {
      if (!summary) {
        return;
      }
      setDetailModal({
        open: true,
        loading: true,
        context,
        entries: [],
        totals: null,
        error: null,
      });
      const payload: {
        startDate: string;
        endDate: string;
        metric: ChannelNumbersDetailMetric;
        channelId?: number;
        productId?: number | null;
        addonKey?: string;
      } = {
        startDate: summary.startDate,
        endDate: summary.endDate,
        metric: context.metric,
      };
      if (typeof context.channelId === 'number') {
        payload.channelId = context.channelId;
      }
      if (context.productId !== undefined) {
        payload.productId = context.productId;
      }
      if (context.addonKey) {
        payload.addonKey = context.addonKey;
      }
      fetchChannelNumbersDetails(payload)
        .then((response) => {
          setDetailModal((prev) => ({
            ...prev,
            loading: false,
            entries: response.entries,
            totals: response.totals,
          }));
        })
        .catch((err) => {
          const message =
            (err as { response?: { data?: { message?: string } } })?.response?.data?.message ??
            (err as { message?: string }).message ??
            'Failed to load metric details';
          setDetailModal((prev) => ({
            ...prev,
            loading: false,
            error: message,
          }));
        });
    },
    [summary],
  );

  const buildDrilldownContext = (
    metric: ChannelNumbersDetailMetric,
    options: {
      channelId?: number;
      channelName?: string;
      productId?: number | null;
      productName?: string;
      addonKey?: string;
      addonName?: string;
      suffix?: string;
    },
  ): DrilldownContext => {
    const parts = [options.channelName, options.productName, options.addonName, options.suffix].filter(
      (part): part is string => Boolean(part && part.trim().length > 0),
    );
    return {
      metric,
      channelId: options.channelId,
      channelName: options.channelName,
      productId: options.productId,
      productName: options.productName,
      addonKey: options.addonKey,
      addonName: options.addonName,
      suffix: options.suffix,
      label: parts.length > 0 ? parts.join(' • ') : 'Metric details',
    };
  };

  const renderValue = useCallback(
    (value: number, context?: DrilldownContext) => {
      const content = <Text fw={value > 0 ? 600 : undefined}>{numberFormatter.format(value)}</Text>;
      if (!context || !summary) {
        return content;
      }
      return (
        <UnstyledButton
          type="button"
          onClick={() => handleShowDetail(context)}
          style={{ width: '100%', display: 'block', textAlign: 'center', color: 'inherit', padding: '0.1rem' }}
          aria-label={context.label}
        >
          {content}
        </UnstyledButton>
      );
    },
    [handleShowDetail, numberFormatter, summary],
  );

  const formatDetailNote = (note?: string | null) => {
    if (!note) {
      return '—';
    }
    const trimmed = note.replace(/\s+/g, ' ').trim();
    if (!trimmed) {
      return '—';
    }
    return trimmed.length > 140 ? `${trimmed.slice(0, 140)}…` : trimmed;
  };

  const renderMetricCard = (label: string, value: number, color: string) => (
    <Paper withBorder p="md" key={label}>
      <Group justify="space-between">
        <Stack gap={2}>
          <Text size="sm" c="dimmed">
            {label}
          </Text>
          <Text size="xl" fw={700}>
            {numberFormatter.format(value)}
          </Text>
        </Stack>
        <ThemeIcon color={color} variant="light" size="lg">
          <IconChartBar size={18} />
        </ThemeIcon>
      </Group>
    </Paper>
  );

  const renderDetailStat = (label: string, value: number, highlighted?: boolean) => (
    <Paper withBorder p="sm" radius="md" key={label} bg={highlighted ? 'var(--mantine-color-gray-0)' : undefined}>
      <Stack gap={2}>
        <Text size="xs" c="dimmed">
          {label}
        </Text>
        <Text fw={highlighted ? 700 : 600} size="lg">
          {numberFormatter.format(value)}
        </Text>
      </Stack>
    </Paper>
  );

  const tableHasData = Boolean(summary && summary.channels.length > 0);
  const currentDetailMetricKey: ChannelNumbersDetailMetric =
    detailModal.context?.metric ?? 'normal';

  return (
    <Stack mt="lg">
      <Paper withBorder p="md">
        <Stack gap="sm">
          <Group justify="space-between" align={isMobile ? 'stretch' : 'flex-end'} gap="sm" wrap="wrap">
            <Stack gap={4} style={{ flex: '1 1 260px', minWidth: 0 }}>
              <Text fw={600}>Reporting period</Text>
              <Group gap="xs" wrap="wrap" grow={isMobile}>
                <Button
                  size={isMobile ? 'sm' : 'xs'}
                  variant={preset === 'thisMonth' ? 'filled' : 'light'}
                  onClick={() => handlePresetChange('thisMonth')}
                >
                  This Month
                </Button>
                <Button
                  size={isMobile ? 'sm' : 'xs'}
                  variant={preset === 'lastMonth' ? 'filled' : 'light'}
                  onClick={() => handlePresetChange('lastMonth')}
                >
                  Last Month
                </Button>
                <Button
                  size={isMobile ? 'sm' : 'xs'}
                  variant={preset === 'custom' ? 'filled' : 'light'}
                  onClick={() => setPreset('custom')}
                >
                  Custom
                </Button>
              </Group>
            </Stack>
            <Box
              w={isMobile ? '100%' : 'auto'}
              style={{ display: 'flex', justifyContent: isMobile ? 'flex-start' : 'flex-end' }}
            >
              {preset === 'custom' ? (
                <DatePickerInput
                  type="range"
                  value={range}
                  onChange={setRange}
                  maxDate={dayjs().endOf('day').toDate()}
                  placeholder="Select range"
                  allowSingleDateInRange
                  style={{ width: isMobile ? '100%' : 260 }}
                />
              ) : (
                <Text size="sm" c="dimmed" style={{ textAlign: isMobile ? 'left' : 'right', width: '100%' }}>
                  {formatDisplayRange(range)}
                </Text>
              )}
            </Box>
          </Group>
          {selectableProductTypes.length > 0 && (
            <MultiSelect
              label="Product types"
              data={selectableProductTypes.map((type) => ({ label: type, value: type }))}
              value={selectedProductTypes}
              onChange={setSelectedProductTypes}
              placeholder="Select product types"
              clearable
              size={isMobile ? 'sm' : 'md'}
            />
          )}
        </Stack>
      </Paper>

      <Paper withBorder p="md" pos="relative">
        <LoadingOverlay visible={loading} zIndex={5} />
        {error && (
          <Alert color="red" icon={<IconAlertCircle size={16} />} mb="md">
            {error}
          </Alert>
        )}
        {summary && (
          <Stack gap="md">
            <SimpleGrid cols={{ base: 1, md: 3 }}>
              {renderMetricCard('Platform total', currentAggregates.platformTotal, 'violet')}
              {renderMetricCard('Attendees', currentAggregates.attendees, 'blue')}
              {renderMetricCard('No-Show', currentAggregates.noShow, 'orange')}
            </SimpleGrid>
            <Paper withBorder p="md">
              <Stack gap="xs">
                <Group justify="space-between">
                  <Text fw={600}>Platform trend</Text>
                  <Group gap="xs">
                    {(previousYearLoading || attendeesChartLoading) && (
                      <Text size="sm" c="dimmed">
                        Loading...
                      </Text>
                    )}
                    <Button
                      size={isMobile ? 'sm' : 'xs'}
                      variant="light"
                      onClick={() => setPlatformTrendFullscreen(true)}
                    >
                      Full screen
                    </Button>
                  </Group>
                </Group>
                <SegmentedControl
                  value={attendeesChartGranularity}
                  onChange={(value) => setAttendeesChartGranularity(value as ChartGranularity)}
                  data={[
                    { label: 'Year by year', value: 'year' },
                    { label: 'Month by month', value: 'month' },
                    { label: 'Week by week', value: 'week' },
                  ]}
                  size={isMobile ? 'sm' : 'xs'}
                  fullWidth={isMobile}
                />
                {renderPlatformTrendChart(isMobile ? 260 : 220)}
              </Stack>
            </Paper>
            {cashSummary && (
              <Paper withBorder p="md">
                <Stack gap="sm">
                  <Group
                    justify="space-between"
                    align={isMobile ? 'flex-start' : 'flex-end'}
                    gap="sm"
                    wrap="wrap"
                  >
                    <div style={{ flex: '1 1 260px', minWidth: 0 }}>
                      <Text fw={600}>Cash collections</Text>
                      <Text size="sm" c="dimmed">
                        Outstanding amounts recorded for cash payment channels
                      </Text>
                    </div>
                    {!cashRangeIsCanonical && (
                      <Box w={isMobile ? '100%' : 'auto'}>
                        <Text size="sm" c="red" ta={isMobile ? 'left' : 'right'}>
                          Collections can only be recorded when viewing a full calendar month.
                        </Text>
                      </Box>
                    )}
                  </Group>
                  {cashRows.length === 0 ? (
                    <Text size="sm" c="dimmed">
                      No cash activity recorded for the selected period.
                    </Text>
                  ) : (
                    <ScrollArea offsetScrollbars type="auto">
                      <Table
                        highlightOnHover
                        withColumnBorders
                        horizontalSpacing="sm"
                        verticalSpacing="xs"
                        miw={600}
                      >
                        <thead>
                          <tr>
                            <th>Channel</th>
                            <th>Currency</th>
                            <th>Due</th>
                            <th>Collected</th>
                            <th>Outstanding</th>
                            <th>Action</th>
                          </tr>
                        </thead>
                        <tbody>
                          {cashRows.map((row) => {
                            const key = `${row.channelId}-${row.currency}`;
                            const canCollect = !isLegacyRange && cashRangeIsCanonical && row.outstandingAmount > 0;
                            return (
                              <tr key={key}>
                                <td>
                                  <Text fw={600}>{row.channelName}</Text>
                                </td>
                                <td>{row.currency}</td>
                                <td>{formatCurrencyValue(row.dueAmount, row.currency)}</td>
                                <td>{formatCurrencyValue(row.collectedAmount, row.currency)}</td>
                                <td>{formatCurrencyValue(row.outstandingAmount, row.currency)}</td>
                                <td>
                                  <Button
                                    size={isMobile ? 'sm' : 'xs'}
                                    variant="light"
                                    disabled={!canCollect}
                                    onClick={() => handleOpenCashModal(row)}
                                  >
                                    Collect
                                  </Button>
                                </td>
                              </tr>
                            );
                          })}
                        </tbody>
                      </Table>
                    </ScrollArea>
                  )}
                  {cashTotals.length > 0 && (
                    <Group gap="lg" wrap="wrap">
                      {cashTotals.map((total) => (
                        <Stack gap={0} key={total.currency}>
                          <Text size="sm" c="dimmed">
                            {total.currency} totals
                          </Text>
                          <Text size="sm">
                            Due {formatCurrencyValue(total.dueAmount, total.currency)} · Collected{' '}
                            {formatCurrencyValue(total.collectedAmount, total.currency)} · Outstanding{' '}
                            {formatCurrencyValue(total.outstandingAmount, total.currency)}
                          </Text>
                        </Stack>
                      ))}
                    </Group>
                  )}
                  {cashEntries.length > 0 && (
                    <Stack gap="xs">
                      <Text fw={600}>Ticket and note summary</Text>
                      <ScrollArea h={240} offsetScrollbars type="auto">
                        <Table
                          striped
                          withColumnBorders
                          highlightOnHover
                          horizontalSpacing="sm"
                          verticalSpacing="xs"
                          miw={720}
                        >
                          <thead>
                            <tr>
                              <th style={{ width: 140 }}>Date</th>
                              <th style={{ width: 180 }}>Channel</th>
                              <th>Tickets</th>
                              <th style={{ width: 200 }}>Amounts</th>
                              <th>Notes</th>
                            </tr>
                          </thead>
                          <tbody>
                            {cashEntries.map((entry: ChannelCashEntry) => (
                              <tr key={`${entry.counterId}-${entry.channelId}`}>
                                <td>{dayjs(entry.counterDate).format('MMM D, YYYY')}</td>
                                <td>{entry.channelName}</td>
                                <td>{entry.ticketSummary ?? '—'}</td>
                                <td>
                                  {entry.amounts.length === 0
                                    ? '—'
                                    : entry.amounts
                                        .map((amount) => formatCurrencyValue(amount.amount, amount.currency))
                                        .join(', ')}
                                </td>
                                <td>{entry.note ?? '—'}</td>
                              </tr>
                            ))}
                          </tbody>
                        </Table>
                      </ScrollArea>
                    </Stack>
                  )}
                </Stack>
              </Paper>
            )}
            {isMobile && (
              <Paper withBorder p="sm">
                <Stack gap="xs">
                  <Group justify="space-between" align="center">
                    <Text fw={600}>Channel totals</Text>
                    <Badge variant="light">{mobileChannelRows.length}</Badge>
                  </Group>
                  <Text size="xs" c="dimmed">
                    Compact view optimized for mobile. Detailed matrix is available below.
                  </Text>
                  {mobileChannelRows.map((row) => (
                    <Paper key={row.channelId} withBorder p="sm" radius="md">
                      <Group justify="space-between" align="flex-start" wrap="nowrap">
                        <Stack gap={2} style={{ minWidth: 0, flex: 1 }}>
                          <Text fw={600} lineClamp={1}>
                            {row.channelName}
                          </Text>
                          <Text size="xs" c="dimmed">
                            Attendees {numberFormatter.format(row.attendees)} · No-Show {numberFormatter.format(row.noShow)}
                          </Text>
                        </Stack>
                        <Text fw={700}>{numberFormatter.format(row.platformTotal)}</Text>
                      </Group>
                    </Paper>
                  ))}
                  <Button
                    fullWidth
                    variant="light"
                    onClick={() => setShowDetailedMatrixMobile((prev) => !prev)}
                  >
                    {showDetailedMatrixMobile ? 'Hide detailed matrix' : 'Show detailed matrix'}
                  </Button>
                </Stack>
              </Paper>
            )}
            {(!isMobile || showDetailedMatrixMobile) && (
              <ScrollArea offsetScrollbars type="auto">
                <Table
                  highlightOnHover
                  withColumnBorders
                  withRowBorders
                  withTableBorder
                  horizontalSpacing={isMobile ? 'xs' : 'sm'}
                  verticalSpacing={isMobile ? 6 : 'xs'}
                  style={{ borderWidth: 2, borderColor: 'var(--mantine-color-gray-5)', minWidth: isMobile ? 860 : undefined }}
                >
                <thead>
                  <tr>
                    <th
                      rowSpan={3}
                      style={mergeCellStyles({
                        textAlign: 'center',
                        borderRight: EMPHASIS_BORDER,
                        borderBottom: EMPHASIS_BORDER,
                      })}
                    >
                      Channel
                    </th>
                    {visibleTypeGroups.map((group, groupIndex) => (
                      <th
                        key={`type-${group.slug}`}
                        colSpan={getTypeColumnCount(group)}
                        style={{
                          ...mergeCellStyles({
                            textAlign: 'center',
                            fontWeight: 700,
                            borderLeft: groupIndex === 0 ? undefined : EMPHASIS_BORDER,
                            borderRight: groupIndex === visibleTypeGroups.length - 1 ? undefined : EMPHASIS_BORDER,
                            borderBottom: EMPHASIS_BORDER,
                          }),
                        }}
                      >
                        {group.name}
                      </th>
                    ))}
                    <th
                      rowSpan={3}
                      style={mergeCellStyles({
                        textAlign: 'center',
                        borderLeft: EMPHASIS_BORDER,
                        borderBottom: EMPHASIS_BORDER,
                        fontWeight: 700,
                      })}
                    >
                      Totals by Platform
                    </th>
                  </tr>
                  <tr>
                    {visibleTypeGroups.flatMap((group, groupIndex) =>
                      group.products.map((product, productIndex) => (
                        <th
                          key={`product-${group.slug}-${product.slug}`}
                          colSpan={getProductColumnCount(product)}
                          style={{
                            ...mergeCellStyles({
                              textAlign: 'center',
                              fontWeight: 600,
                              borderBottom: EMPHASIS_BORDER,
                            }),
                            borderLeft: EMPHASIS_BORDER,
                            borderRight:
                              productIndex === group.products.length - 1
                                ? groupIndex === visibleTypeGroups.length - 1
                                  ? undefined
                                  : EMPHASIS_BORDER
                                : undefined,
                          }}
                        >
                          {product.name}
                        </th>
                      )),
                    )}
                  </tr>
                  <tr>
                    {visibleTypeGroups.flatMap((group, groupIndex) =>
                      group.products.flatMap((product, productIndex) =>
                        product.addons.length > 0
                          ? [
                              <th
                                key={`label-normal-${group.slug}-${product.slug}`}
                                style={{
                                  ...mergeCellStyles({ textAlign: 'center', fontWeight: 600 }),
                                  borderLeft: EMPHASIS_BORDER,
                                  borderBottom: EMPHASIS_BORDER,
                                }}
                              >
                                Normal
                              </th>,
                              <th
                                key={`label-nonshow-${group.slug}-${product.slug}`}
                                style={mergeCellStyles(
                                  { textAlign: 'center', fontWeight: 600, borderBottom: EMPHASIS_BORDER },
                                  NO_LEFT_BORDER,
                                )}
                              >
                                Non-Show
                              </th>,
                              ...product.addons.flatMap((addon, addonIndex) => [
                                <th
                                  key={`label-addon-${group.slug}-${product.slug}-${addon.key}`}
                                  style={mergeCellStyles({
                                    textAlign: 'center',
                                    fontWeight: 600,
                                    borderBottom: EMPHASIS_BORDER,
                                  })}
                                >
                                  {addon.name}
                                </th>,
                                <th
                                  key={`label-addon-nonshow-${group.slug}-${product.slug}-${addon.key}`}
                                  style={mergeCellStyles(
                                    {
                                      textAlign: 'center',
                                      fontWeight: 600,
                                      borderBottom: EMPHASIS_BORDER,
                                    },
                                    NO_LEFT_BORDER,
                                    addonIndex === product.addons.length - 1 &&
                                      (groupIndex !== visibleTypeGroups.length - 1 ||
                                        productIndex !== group.products.length - 1)
                                      ? { borderRight: EMPHASIS_BORDER }
                                      : undefined,
                                  )}
                                >
                                  {`${addon.name} (Non-Show)`}
                                </th>,
                              ]),
                            ]
                          : [
                                <th
                                  key={`label-quantity-${group.slug}-${product.slug}`}
                                  style={{
                                    ...mergeCellStyles({ textAlign: 'center', fontWeight: 600 }),
                                    borderLeft: EMPHASIS_BORDER,
                                    borderBottom: EMPHASIS_BORDER,
                                  }}
                                >
                                  Quantity
                                </th>,
                                <th
                                  key={`label-quantity-nonshow-${group.slug}-${product.slug}`}
                                  style={mergeCellStyles(
                                    {
                                      textAlign: 'center',
                                      fontWeight: 600,
                                      borderBottom: EMPHASIS_BORDER,
                                    },
                                    NO_LEFT_BORDER,
                                    productIndex === group.products.length - 1 && groupIndex !== visibleTypeGroups.length - 1
                                      ? { borderRight: EMPHASIS_BORDER }
                                      : undefined,
                                  )}
                                >
                                  Non-Show
                                </th>,
                              ],
                      ),
                    )}
                  </tr>
                </thead>
                <tbody>
                  {tableHasData ? (
                    summary.channels.map((channel) => {
                      const filteredChannelTotal = currentAggregates.channelTotals.get(channel.channelId) ?? 0;
                      return (
                        <tr key={channel.channelId}>
                          <td style={mergeCellStyles({ borderRight: EMPHASIS_BORDER })}>
                            <Text fw={600}>{channel.channelName}</Text>
                          </td>
                              {visibleTypeGroups.flatMap((group, groupIndex) =>
                                group.products.flatMap((product, productIndex) => {
                                  const isLastProductInGroup = productIndex === group.products.length - 1;
                                  const productKey = getProductKey(product.id);
                                  const productMetrics = channel.products?.[productKey];
                                  const numericProductId =
                                    typeof product.id === 'number' ? product.id : productMetrics?.productId ?? undefined;
                                  const baseContextOptions = {
                                    channelId: channel.channelId,
                                    channelName: channel.channelName,
                                    productId: numericProductId,
                                    productName: product.name,
                                  };
                                  if (product.addons.length > 0) {
                                    const normalValue = productMetrics?.normal ?? 0;
                                    const nonShowValue = productMetrics?.nonShow ?? 0;
                                    const normalContext = buildDrilldownContext('normal', {
                                      ...baseContextOptions,
                                      suffix: 'Normal',
                                    });
                                    const nonShowContext = buildDrilldownContext('nonShow', {
                                      ...baseContextOptions,
                                      suffix: 'Non-Show',
                                    });
                                    return [
                                      <td
                                        key={`normal-${group.slug}-${product.slug}-${channel.channelId}`}
                                        style={mergeCellStyles({
                                          fontWeight:
                                            group.slug === MAIN_PRODUCT_TYPE_SLUG && normalValue > 0 ? 600 : undefined,
                                          borderLeft: EMPHASIS_BORDER,
                                        })}
                                      >
                                        {renderValue(normalValue, normalContext)}
                                      </td>,
                                      <td
                                        key={`nonshow-${group.slug}-${product.slug}-${channel.channelId}`}
                                        style={mergeCellStyles(NO_LEFT_BORDER)}
                                      >
                                        {renderValue(nonShowValue, nonShowContext)}
                                      </td>,
                                      ...product.addons.flatMap((addon, addonIndex) => [
                                        <td
                                          key={`addon-${group.slug}-${product.slug}-${addon.key}-${channel.channelId}`}
                                          style={mergeCellStyles()}
                                        >
                                          {renderValue(
                                            productMetrics?.addons?.[addon.key] ?? 0,
                                            buildDrilldownContext('addon', {
                                              ...baseContextOptions,
                                              addonKey: addon.key,
                                              addonName: addon.name,
                                            }),
                                          )}
                                        </td>,
                                        <td
                                          key={`addon-nonshow-${group.slug}-${product.slug}-${addon.key}-${channel.channelId}`}
                                          style={mergeCellStyles(
                                            NO_LEFT_BORDER,
                                            isLastProductInGroup &&
                                              addonIndex === product.addons.length - 1 &&
                                              groupIndex !== visibleTypeGroups.length - 1
                                              ? { borderRight: EMPHASIS_BORDER }
                                              : undefined,
                                          )}
                                        >
                                          {renderValue(
                                            productMetrics?.addonNonShow?.[addon.key] ?? 0,
                                            buildDrilldownContext('addonNonShow', {
                                              ...baseContextOptions,
                                              addonKey: addon.key,
                                              addonName: addon.name,
                                              suffix: 'Non-Show',
                                            }),
                                          )}
                                        </td>,
                                      ]),
                                    ];
                                  }
                                  const quantityContext = buildDrilldownContext('normal', {
                                    ...baseContextOptions,
                                    suffix: 'Quantity',
                                  });
                                  const productNonShowContext = buildDrilldownContext('nonShow', {
                                    ...baseContextOptions,
                                    suffix: 'Non-Show',
                                  });
                                  return [
                                    <td
                                      key={`quantity-${group.slug}-${product.slug}-${channel.channelId}`}
                                      style={mergeCellStyles(
                                        { borderLeft: EMPHASIS_BORDER },
                                      )}
                                    >
                                      {renderValue(getQuantityForProduct(product, productMetrics), quantityContext)}
                                    </td>,
                                    <td
                                      key={`quantity-nonshow-${group.slug}-${product.slug}-${channel.channelId}`}
                                      style={mergeCellStyles(
                                        NO_LEFT_BORDER,
                                        isLastProductInGroup && groupIndex !== visibleTypeGroups.length - 1
                                          ? { borderRight: EMPHASIS_BORDER }
                                          : undefined,
                                      )}
                                    >
                                      {renderValue(productMetrics?.nonShow ?? 0, productNonShowContext)}
                                    </td>,
                                  ];
                                }),
                              )}
                          <td style={mergeCellStyles({ fontWeight: 600, borderLeft: EMPHASIS_BORDER })}>
                            {renderValue(
                              filteredChannelTotal,
                              !isProductTypeFilterActive
                                ? buildDrilldownContext('total', {
                                  channelId: channel.channelId,
                                  channelName: channel.channelName,
                                  suffix: 'Platform Total',
                                })
                                : undefined,
                            )}
                          </td>
                        </tr>
                      );
                    })
                  ) : (
                    <tr>
                      <td
                        colSpan={1 + totalTypeColumns + 1}
                        style={mergeCellStyles({ textAlign: 'center', borderLeft: EMPHASIS_BORDER, borderRight: EMPHASIS_BORDER })}
                      >
                        <Group justify="center" gap="xs">
                          <IconInfoCircle size={16} />
                          <Text c="dimmed" size="sm">
                            No channel metrics available for the selected period.
                          </Text>
                        </Group>
                      </td>
                    </tr>
                  )}
                </tbody>
                {tableHasData && (
                  <tfoot>
                    <tr>
                      <td style={mergeCellStyles({ borderRight: EMPHASIS_BORDER, borderTop: EMPHASIS_BORDER })}>
                        <Text fw={700}>Total</Text>
                      </td>
                      {visibleTypeGroups.flatMap((group, groupIndex) =>
                        group.products.flatMap((product, productIndex) => {
                          const isLastProductInGroup = productIndex === group.products.length - 1;
                          const productKey = getProductKey(product.id);
                          const productTotals = summary.productTotals?.[productKey];
                          const totalsProductId =
                            typeof product.id === 'number' ? product.id : productTotals?.productId ?? undefined;
                          const totalsContextBase = {
                            productId: totalsProductId,
                            productName: product.name,
                          };
                          if (product.addons.length > 0) {
                            const normalTotal = productTotals?.normal ?? 0;
                            const nonShowTotal = productTotals?.nonShow ?? 0;
                            return [
                              <td
                                key={`total-normal-${group.slug}-${product.slug}`}
                                style={mergeCellStyles({ borderTop: EMPHASIS_BORDER, borderLeft: EMPHASIS_BORDER })}
                              >
                                {renderValue(
                                  normalTotal,
                                  buildDrilldownContext('normal', {
                                    ...totalsContextBase,
                                    suffix: 'Normal (All Channels)',
                                  }),
                                )}
                              </td>,
                              <td
                                key={`total-nonshow-${group.slug}-${product.slug}`}
                                style={mergeCellStyles({ borderTop: EMPHASIS_BORDER }, NO_LEFT_BORDER)}
                              >
                                {renderValue(
                                  nonShowTotal,
                                  buildDrilldownContext('nonShow', {
                                    ...totalsContextBase,
                                    suffix: 'Non-Show (All Channels)',
                                  }),
                                )}
                              </td>,
                              ...product.addons.flatMap((addon, addonIndex) => [
                                <td
                                  key={`total-addon-${group.slug}-${product.slug}-${addon.key}`}
                                  style={mergeCellStyles({ borderTop: EMPHASIS_BORDER })}
                                >
                                  {renderValue(
                                    productTotals?.addons?.[addon.key] ?? 0,
                                    buildDrilldownContext('addon', {
                                      ...totalsContextBase,
                                      addonKey: addon.key,
                                      addonName: addon.name,
                                    }),
                                  )}
                                </td>,
                                <td
                                  key={`total-addon-nonshow-${group.slug}-${product.slug}-${addon.key}`}
                                  style={mergeCellStyles(
                                    { borderTop: EMPHASIS_BORDER },
                                    NO_LEFT_BORDER,
                                    isLastProductInGroup &&
                                      addonIndex === product.addons.length - 1 &&
                                      groupIndex !== visibleTypeGroups.length - 1
                                      ? { borderRight: EMPHASIS_BORDER }
                                      : undefined,
                                  )}
                                >
                                  {renderValue(
                                    productTotals?.addonNonShow?.[addon.key] ?? 0,
                                    buildDrilldownContext('addonNonShow', {
                                      ...totalsContextBase,
                                      addonKey: addon.key,
                                      addonName: addon.name,
                                      suffix: 'Non-Show',
                                    }),
                                  )}
                                </td>,
                              ]),
                            ];
                          }
                          return [
                            <td
                              key={`total-quantity-${group.slug}-${product.slug}`}
                              style={mergeCellStyles(
                                { borderTop: EMPHASIS_BORDER, borderLeft: EMPHASIS_BORDER },
                              )}
                            >
                                {renderValue(
                                  getQuantityForProduct(product, productTotals),
                                  buildDrilldownContext('normal', {
                                    ...totalsContextBase,
                                    suffix: 'Quantity (All Channels)',
                                  }),
                                )}
                            </td>,
                            <td
                              key={`total-quantity-nonshow-${group.slug}-${product.slug}`}
                              style={mergeCellStyles(
                                { borderTop: EMPHASIS_BORDER },
                                NO_LEFT_BORDER,
                                isLastProductInGroup && groupIndex !== visibleTypeGroups.length - 1
                                  ? { borderRight: EMPHASIS_BORDER }
                                  : undefined,
                              )}
                            >
                              {renderValue(
                                productTotals?.nonShow ?? 0,
                                buildDrilldownContext('nonShow', {
                                  ...totalsContextBase,
                                  suffix: 'Non-Show (All Channels)',
                                }),
                              )}
                            </td>,
                          ];
                        }),
                      )}
                      <td style={mergeCellStyles({ borderLeft: EMPHASIS_BORDER, borderTop: EMPHASIS_BORDER })}>
                        {renderValue(
                          currentAggregates.platformTotal,
                          !isProductTypeFilterActive
                            ? buildDrilldownContext('total', {
                              suffix: 'Grand Total',
                            })
                            : undefined,
                        )}
                      </td>
                    </tr>
                  </tfoot>
                )}
                </Table>
              </ScrollArea>
            )}
          </Stack>
        )}
        {!loading && !summary && !error && (
          <Stack align="center" gap={4} mt="md">
            <IconInfoCircle size={20} />
            <Text size="sm" c="dimmed">
              Select a reporting range to load channel metrics.
            </Text>
          </Stack>
        )}
      </Paper>
      <Modal
        opened={platformTrendFullscreen}
        onClose={() => setPlatformTrendFullscreen(false)}
        title=""
        withCloseButton={false}
        fullScreen
        radius={0}
        styles={{
          content: { height: '100dvh', overflow: 'hidden' },
          header: { display: 'none' },
          body: {
            height: '100dvh',
            padding: 8,
            overflow: 'hidden',
          },
        }}
      >
        {usePseudoLandscapeFullscreen ? (
          <Box style={{ height: '100%', display: 'flex', flexDirection: 'column', gap: 10, minHeight: 0, overflow: 'hidden' }}>
            <Group justify="center" align="center" style={{ position: 'relative', minHeight: 32 }}>
              <Text fw={700} ta="center" style={{ width: '100%' }}>
                Platform trend
              </Text>
              <Button
                size="xs"
                variant="default"
                px={8}
                style={{ position: 'absolute', right: 0, top: '50%', transform: 'translateY(-50%)' }}
                onClick={() => setPlatformTrendFullscreen(false)}
                aria-label="Close full screen"
              >
                x
              </Button>
            </Group>
            <Box style={{ flex: 1, minHeight: 0, overflow: 'visible', display: 'flex', gap: 8 }}>
              <Box
                ref={fullscreenTrendChartAreaRef}
                style={{
                  flex: 1,
                  minWidth: 0,
                  minHeight: 0,
                  overflow: 'visible',
                  touchAction: 'manipulation',
                  position: 'relative',
                  zIndex: 3,
                }}
              >
                {renderPlatformTrendChart('100%', true, true)}
              </Box>
              <Stack
                gap="xs"
                style={{
                  width: 112,
                  minWidth: 112,
                  justifyContent: 'center',
                  position: 'relative',
                  zIndex: 1,
                }}
              >
                <Button
                  size="xs"
                  variant={attendeesChartGranularity === 'year' ? 'filled' : 'light'}
                  onClick={() => setAttendeesChartGranularity('year')}
                  fullWidth
                >
                  Year by year
                </Button>
                <Button
                  size="xs"
                  variant={attendeesChartGranularity === 'month' ? 'filled' : 'light'}
                  onClick={() => setAttendeesChartGranularity('month')}
                  fullWidth
                >
                  Month by month
                </Button>
                <Button
                  size="xs"
                  variant={attendeesChartGranularity === 'week' ? 'filled' : 'light'}
                  onClick={() => setAttendeesChartGranularity('week')}
                  fullWidth
                >
                  Week by week
                </Button>
              </Stack>
            </Box>
          </Box>
        ) : (
          <Box style={{ height: '100%', display: 'flex', flexDirection: 'column', gap: 12, minHeight: 0, overflow: 'hidden' }}>
            <Group justify="center" align="center" style={{ position: 'relative', minHeight: 32 }}>
              <Text fw={700} ta="center" style={{ width: '100%' }}>
                Platform trend
              </Text>
              <Button
                size={isMobile ? 'sm' : 'xs'}
                variant="default"
                px={8}
                style={{ position: 'absolute', right: 0, top: '50%', transform: 'translateY(-50%)' }}
                onClick={() => setPlatformTrendFullscreen(false)}
                aria-label="Close full screen"
              >
                x
              </Button>
            </Group>
            <SegmentedControl
              value={attendeesChartGranularity}
              onChange={(value) => setAttendeesChartGranularity(value as ChartGranularity)}
              data={[
                { label: 'Year by year', value: 'year' },
                { label: 'Month by month', value: 'month' },
                { label: 'Week by week', value: 'week' },
              ]}
              size={isMobile ? 'sm' : 'md'}
              fullWidth
            />
            <Box
              ref={fullscreenTrendChartAreaRef}
              style={{ flex: 1, minHeight: 0, overflow: 'hidden', touchAction: 'manipulation' }}
            >
              {renderPlatformTrendChart('100%', true)}
            </Box>
          </Box>
        )}
      </Modal>
      <Modal
        opened={cashModal.open}
        onClose={handleCloseCashModal}
        title="Record cash collection"
        centered
        fullScreen={isMobile}
      >
        <Stack gap="sm">
          {cashModal.channel && (
            <Stack gap={0}>
              <Text fw={600}>{cashModal.channel.channelName}</Text>
              <Text size="sm" c="dimmed">
                Outstanding: {formatCurrencyValue(cashModal.channel.outstandingAmount, cashModal.currency)}
              </Text>
            </Stack>
          )}
          <NumberInput
            label="Amount"
            value={cashModal.amount}
            onChange={(value) =>
              setCashModal((prev) => ({
                ...prev,
                amount: typeof value === 'number' ? value : 0,
              }))
            }
            min={0}
            decimalScale={2}
            fixedDecimalScale
            hideControls
          />
          <Select
            label="Account"
            data={accountOptions}
            value={cashModal.accountId}
            onChange={(value) => setCashModal((prev) => ({ ...prev, accountId: value ?? '' }))}
            placeholder="Select account"
          />
          <Select
            label="Income category"
            data={incomeCategoryOptions}
            value={cashModal.categoryId}
            onChange={(value) => setCashModal((prev) => ({ ...prev, categoryId: value ?? '' }))}
            placeholder="Select category"
          />
          <Select
            label="Client"
            data={clientOptions}
            value={cashModal.counterpartyId}
            onChange={(value) => setCashModal((prev) => ({ ...prev, counterpartyId: value ?? '' }))}
            placeholder="Select client"
          />
          <DatePickerInput
            label="Date"
            value={cashModal.date}
            onChange={(value) => setCashModal((prev) => ({ ...prev, date: value ?? new Date() }))}
          />
          <Textarea
            label="Description"
            value={cashModal.description}
            onChange={(event) => setCashModal((prev) => ({ ...prev, description: event.currentTarget.value }))}
            minRows={2}
          />
          {cashMessage && (
            <Alert color="red" variant="light">
              {cashMessage}
            </Alert>
          )}
          <Group justify="flex-end" gap="sm">
            <Button variant="default" onClick={handleCloseCashModal}>
              Cancel
            </Button>
            <Button onClick={handleCashSubmit} loading={cashSubmitting} disabled={!cashModal.channel}>
              Record collection
            </Button>
          </Group>
        </Stack>
      </Modal>
      <Modal
        opened={detailModal.open}
        onClose={handleCloseDetailModal}
        title={detailModal.context?.label ?? 'Metric details'}
        size={isMobile ? '100%' : 'xl'}
        fullScreen={isMobile}
        centered
        radius="lg"
        scrollAreaComponent={ScrollArea.Autosize}
      >
        <Stack gap="md">
          {detailModal.context && (
            <Group justify="space-between" align="flex-start">
              <Stack gap={2}>
                <Text fw={600}>{detailModal.context.channelName ?? 'All channels'}</Text>
                <Text size="sm" c="dimmed">
                  {detailModal.context.productName ?? 'All products'}
                </Text>
              </Stack>
              <Badge color={DETAIL_METRIC_META[currentDetailMetricKey].color} variant="light">
                {DETAIL_METRIC_META[currentDetailMetricKey].label}
              </Badge>
            </Group>
          )}
          {detailModal.context?.addonName && (
            <Text size="sm" c="dimmed">
              Add-on: <Text span fw={600}>{detailModal.context.addonName}</Text>
            </Text>
          )}
          {detailModal.context?.suffix && (
            <Text size="sm" c="dimmed">
              {detailModal.context.suffix}
            </Text>
          )}
          {detailModal.error && (
            <Alert color="red" variant="light">
              {detailModal.error}
            </Alert>
          )}
          {detailModal.totals && (
            <SimpleGrid cols={{ base: 1, sm: 2, md: 3, lg: 5 }}>
              {renderDetailStat('Booked (Before)', detailModal.totals.bookedBefore)}
              {renderDetailStat('Booked (After)', detailModal.totals.bookedAfter)}
              {renderDetailStat('Attended', detailModal.totals.attended)}
              {renderDetailStat('Non-Show', detailModal.totals.nonShow)}
              {renderDetailStat(
                DETAIL_METRIC_META[currentDetailMetricKey].totalLabel,
                detailModal.totals.value,
                true,
              )}
            </SimpleGrid>
          )}
          <Paper withBorder p="sm" radius="md" style={{ position: 'relative', maxHeight: '70vh' }}>
            <LoadingOverlay visible={detailModal.loading} zIndex={5} />
            <ScrollArea maw="100%" h="60vh" offsetScrollbars type="always">
              {detailModal.entries.length > 0 ? (
                <Table
                  striped
                  highlightOnHover
                  withColumnBorders
                  stickyHeader
                  horizontalSpacing="md"
                  verticalSpacing="sm"
                  style={{ minWidth: 960, fontVariantNumeric: 'tabular-nums' }}
                >
                  <Table.Thead>
                    <Table.Tr>
                      <Table.Th>Date</Table.Th>
                      <Table.Th>Channel</Table.Th>
                      <Table.Th>Product</Table.Th>
                      <Table.Th>Addon</Table.Th>
                      <Table.Th>Booked (Before)</Table.Th>
                      <Table.Th>Booked (After)</Table.Th>
                      <Table.Th>Attended</Table.Th>
                      <Table.Th>Non-Show</Table.Th>
                      <Table.Th>Value</Table.Th>
                      <Table.Th>Notes</Table.Th>
                    </Table.Tr>
                  </Table.Thead>
                  <Table.Tbody>
                    {detailModal.entries.map((entry) => (
                      <Table.Tr key={`${entry.counterId}-${entry.channelId}-${entry.addonKey ?? 'none'}`}>
                        <Table.Td>{dayjs(entry.counterDate).format('MMM D, YYYY')}</Table.Td>
                        <Table.Td>{entry.channelName}</Table.Td>
                        <Table.Td>{entry.productName ?? '—'}</Table.Td>
                        <Table.Td>{entry.addonName ?? '—'}</Table.Td>
                        <Table.Td>{numberFormatter.format(entry.bookedBefore)}</Table.Td>
                        <Table.Td>{numberFormatter.format(entry.bookedAfter)}</Table.Td>
                        <Table.Td>{numberFormatter.format(entry.attended)}</Table.Td>
                        <Table.Td>{numberFormatter.format(entry.nonShow)}</Table.Td>
                        <Table.Td>{numberFormatter.format(entry.value)}</Table.Td>
                        <Table.Td style={{ maxWidth: 220 }}>
                          <Text size="sm" c="dimmed" lineClamp={2}>
                            {formatDetailNote(entry.note)}
                          </Text>
                        </Table.Td>
                      </Table.Tr>
                    ))}
                  </Table.Tbody>
                  {detailModal.totals && (
                    <Table.Tfoot>
                      <Table.Tr>
                        <Table.Th colSpan={4}>Totals</Table.Th>
                        <Table.Th>{numberFormatter.format(detailModal.totals.bookedBefore)}</Table.Th>
                        <Table.Th>{numberFormatter.format(detailModal.totals.bookedAfter)}</Table.Th>
                        <Table.Th>{numberFormatter.format(detailModal.totals.attended)}</Table.Th>
                        <Table.Th>{numberFormatter.format(detailModal.totals.nonShow)}</Table.Th>
                        <Table.Th>{numberFormatter.format(detailModal.totals.value)}</Table.Th>
                        <Table.Th />
                      </Table.Tr>
                    </Table.Tfoot>
                  )}
                </Table>
              ) : (
                <Center py="md">
                  <Text size="sm" c="dimmed">
                    {detailModal.loading
                      ? 'Loading metric details...'
                      : 'No daily entries found for this selection.'}
                  </Text>
                </Center>
              )}
            </ScrollArea>
          </Paper>
        </Stack>
      </Modal>
    </Stack>
  );
};

export default ChannelNumbersSummary;
